questions.text:
Trace the following code. What is the output?

```cpp
int count = 1;
while (count <= 4) {
    cout << count << " ";
    count++;
}
```

What is the output of the following code snippet?

```cpp
for (int i = 1; i < 5; i++) {
    if (i == 3) continue;
    cout << i << " ";
}
```

What is the output of the following code snippet?

```cpp
int x = 5;
do {
    cout << x << " ";
    x = x - 2;
} while (x > 0);
```

How many times will the word "Hello" be printed?

```cpp
for (int i = 0; i < 3; i++) {
    for (int j = 0; j < 2; j++) {
        cout << "Hello" << endl;
    }
}
```

What is the output of the following code?

```cpp
int i = 0;
while (i < 5) {
    if (i == 2) break;
    cout << i << " ";
    i++;
}
```

Trace the values of `sum`. What is the final value of `sum` after this loop?

```cpp
int sum = 0;
for (int i = 1; i <= 5; i += 2) {
    sum += i;
}
```

What is the output of the following code snippet?

```cpp
int j = 10;
while (j > 7) {
    j--;
    cout << j << " ";
}
```

What is the result of the following nested loop?

```cpp
for (int i = 1; i <= 2; i++) {
    for (int j = 1; j <= 3; j++) {
        if (j == 2) continue;
        cout << i << j << " ";
    }
}
```

What is the output of the following code snippet?

```cpp
int x = 1;
while (x < 10) {
    x *= 3;
}
cout << x;
```

Determine the output of this code:

```cpp
int k = 0;
for (int i = 0; i < 5; i++) {
    if (i % 2 == 0) k += i;
    else k--;
}
cout << k;
```

What does the following code print?

```cpp
int a = 0;
do {
    a++;
    if (a == 3) break;
} while (a < 5);
cout << a;
```

Identify the output of the following code:

```cpp
for (int i = 5; i >= 1; i--) {
    if (i == 3) break;
    cout << i << ",";
}
```

Trace the output of this code snippet:

```cpp
int n = 2;
while (n < 20) {
    n = n * n;
    cout << n << " ";
}
```

What is the result of the following code?

```cpp
int m = 0;
for (int i = 0; i < 2; i++) {
    for (int j = 0; j < 2; j++) {
        m = m + i + j;
    }
}
cout << m;
```

What is the output of the following loop?

```cpp
int p = 1;
while (p < 5) {
    p++;
    if (p == 3) continue;
    cout << p << " ";
}
```
